// friday13.cs â€” Find earliest Friday the 13th and count them in a 400-year cycle

// Find the earliest Friday the 13th starting from 0001-01-01 (proleptic Gregorian)
DateOnly earliest = default;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            if (earliest == default)
                earliest = d;
            break; // only need first per year for the "earliest" search
        }
    }
    if (earliest != default) break;
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");

// Count all Friday the 13ths in one full 400-year Gregorian cycle (years 1â€“400)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");

// Bonus: distribution by day-of-week for the 13th
Console.WriteLine("\nDistribution of day-of-week for the 13th (400-year cycle):");
var dow = new int[7];
for (int year = 1; year <= 400; year++)
    for (int month = 1; month <= 12; month++)
        dow[(int)new DateOnly(year, month, 13).DayOfWeek]++;

for (int i = 0; i < 7; i++)
    Console.WriteLine($"  {(DayOfWeek)i,-10}: {dow[i]}");

